// ═══════════════════════════════════════
// JSON SCHEMA VALIDATOR (manual)
// ═══════════════════════════════════════
// 1. Intenta parsear el output del LLM
// 2. Chequea que cumpla el shape esperado
// 3. Acumula errors[] y setea schemaValid

const llmResponse = $input.first().json;
const content = llmResponse?.choices?.[0]?.message?.content;

function tryParse(s) {
  if (typeof s !== 'string') return null;
  try { return JSON.parse(s); } catch (e) {}
  const cleaned = s.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/, '').trim();
  try { return JSON.parse(cleaned); } catch (e) {}
  return null;
}

const parsed = tryParse(content);
const errors = [];

if (!parsed) {
  errors.push('no se pudo parsear el output como JSON');
} else {
  const validUrgency = ['P1', 'P2', 'P3', 'P4'];
  if (!validUrgency.includes(parsed.urgency)) {
    errors.push(`urgency debe ser P1/P2/P3/P4 (recibido: ${parsed.urgency})`);
  }
  if (typeof parsed.reasoning !== 'string' || parsed.reasoning.trim().length === 0) {
    errors.push('reasoning debe ser string no vacío');
  }
}

const schemaValid = errors.length === 0;

return [{
  json: {
    schemaValid,
    errors,
    parsed,
    rawContent: content
  }
}];
